const e=JSON.parse('{"key":"v-01cac900","path":"/webpack/webapck%E5%9F%BA%E7%A1%80%E9%85%8D%E7%BD%AE.html","title":"webapck基础配置","lang":"zh-CN","frontmatter":{"title":"webapck基础配置","isTimeLine":true,"date":"2026-03-10T00:00:00.000Z","category":["前端"],"tag":["JavaScript","webpack"]},"headers":[{"level":3,"title":"为什么需要打包工具?","slug":"为什么需要打包工具","link":"#为什么需要打包工具","children":[]},{"level":3,"title":"对webpack的理解？","slug":"对webpack的理解","link":"#对webpack的理解","children":[]},{"level":3,"title":"webpack怎么使用","slug":"webpack怎么使用","link":"#webpack怎么使用","children":[]},{"level":3,"title":"常见的Loader？","slug":"常见的loader","link":"#常见的loader","children":[]},{"level":3,"title":"常见的Plugin？","slug":"常见的plugin","link":"#常见的plugin","children":[]},{"level":3,"title":"基础配置","slug":"基础配置","link":"#基础配置","children":[]}],"git":{"createdTime":1773238261000,"updatedTime":1773238261000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":7.19,"words":2157},"filePathRelative":"webpack/webapck基础配置.md","localizedDate":"2026年3月10日","excerpt":"<h3> 为什么需要打包工具?</h3>\\n<ol>\\n<li>编译功能：我们在项目使用的<code>框架、less、sass、es6</code>等浏览器都不能识别，需要打包工具编译成<code>css js</code>等语法才能运行</li>\\n<li>还可以压缩代码、做兼容性处理、提高代码性能</li>\\n<li>主要的打包工具：<code>webpack vite rollup</code>等</li>\\n</ol>\\n<h3> 对webpack的理解？</h3>\\n<ol>\\n<li>是一个静态资源打包工具，它以一个或多个文件作为打包的入口，将整个项目的文件编译成一个或多个文件输出出去，输出文件bundle就是编译好的文件，浏览器可以运行。本身功能有限制，只能编译js的ES Module语法.</li>\\n<li>可以做什么？<br>\\n① 编译代码，编译高级的语言或语法（<code>TS、ES6+、sass</code>等）；<br>\\n② 模块整合，在项目中有很多模块和文件，合并之后可以，解决浏览器频繁请求文件的问题；<br>\\n③ 兼容性和错误检查（<code>Polyfill、postcss、eslint</code>）；<br>\\n④ 代码体积更小，加载更快（<code>Tree-shaking、压缩、合并</code>）</li>\\n</ol>"}');export{e as data};
